function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const INF = Number.MAX_SAFE_INTEGER;

    const dist: number[][][] = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dist[i][j] = new Array(k+1).fill(INF);
        }
    }

    dist[0][0][0] = 0;
    const heap: [number, number, number, number][] = [];
    heap.push([0, 0, 0, 0]);

    while (heap.length > 0) {
        heap.sort((a, b) => a[0] - b[0]);
        const [cost, i, j, t] = heap.shift()!;

        if (cost !== dist[i][j][t]) continue;

        if (i === m-1 && j === n-1) {
            return cost;
        }

        const dirs = [[1,0], [0,1]];
        for (const [dx, dy] of dirs) {
            const ni = i + dx;
            const nj = j + dy;
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                const newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = newCost;
                    heap.push([newCost, ni, nj, t]);
                }
            }
        }

        if (t < k) {
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        if (cost < dist[x][y][t+1]) {
                            dist[x][y][t+1] = cost;
                            heap.push([cost, x, y, t+1]);
                        }
                    }
                }
            }
        }
    }

    let ans = INF;
    for (let t = 0; t <= k; t++) {
        ans = Math.min(ans, dist[m-1][n-1][t]);
    }
    return ans;
}
