function solve(grid: number[][], k: number): number {
    class MinHeap {
        heap: {i: number, j: number, cost: number}[];

        constructor() {
            this.heap = [];
        }

        enqueue(i: number, j: number, cost: number): void {
            this.heap.push({i, j, cost});
            this.bubbleUp(this.heap.length - 1);
        }

        bubbleUp(idx: number): void {
            if (idx === 0) return;
            const parentIdx = Math.floor((idx - 1) / 2);
            if (this.heap[parentIdx].cost > this.heap[idx].cost) {
                [this.heap[parentIdx], this.heap[idx]] = [this.heap[idx], this.heap[parentIdx]];
                this.bubbleUp(parentIdx);
            }
        }

        dequeue(): {i: number, j: number, cost: number} | null {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            const last = this.heap.pop();
            if (this.heap.length > 0 && last) {
                this.heap[0] = last;
                this.sinkDown(0);
            }
            return min;
        }

        sinkDown(idx: number): void {
            let min = idx;
            const left = 2 * idx + 1;
            const right = 2 * idx + 2;

            if (left < this.heap.length && this.heap[left].cost < this.heap[min].cost) {
                min = left;
            }
            if (right < this.heap.length && this.heap[right].cost < this.heap[min].cost) {
                min = right;
            }
            if (min !== idx) {
                [this.heap[idx], this.heap[min]] = [this.heap[min], this.heap[idx]];
                this.sinkDown(min);
            }
        }

        isEmpty(): boolean {
            return this.heap.length === 0;
        }
    }

    const m = grid.length;
    const n = grid[0].length;
    const INF = 1e15;

    const dp: number[][][] = Array.from({ length: k+1 }, () => 
        Array.from({ length: m }, () => 
            Array(n).fill(INF)
        )
    );

    dp[0][0][0] = 0;

    for (let t = 0; t <= k; t++) {
        const heap = new MinHeap();
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (dp[t][i][j] < INF) {
                    heap.enqueue(i, j, dp[t][i][j]);
                }
            }
        }

        while (!heap.isEmpty()) {
            const node = heap.dequeue();
            if (!node) break;
            const { i, j, cost } = node;
            if (cost !== dp[t][i][j]) continue;

            const directions = [[0, 1], [1, 0]];
            for (const [dx, dy] of directions) {
                const ni = i + dx;
                const nj = j + dy;
                if (ni < 0 || ni >= m || nj < 0 || nj >= n) continue;
                const newCost = cost + grid[ni][nj];
                if (newCost < dp[t][ni][nj]) {
                    dp[t][ni][nj] = newCost;
                    heap.enqueue(ni, nj, newCost);
                }
            }
        }

        if (t < k) {
            const list: [number, number][] = [];
            for (let i = 0; i < m; i++) {
                for (let j = 0; j < n; j++) {
                    if (dp[t][i][j] < INF) {
                        list.push([grid[i][j], dp[t][i][j]]);
                    }
                }
            }
            if (list.length === 0) continue;
            list.sort((a, b) => b[0] - a[0]);
            const minSuffix: number[] = new Array(list.length);
            minSuffix[0] = list[0][1];
            for (let i = 1; i < list.length; i++) {
                minSuffix[i] = Math.min(minSuffix[i-1], list[i][1]);
            }
            for (let i = 0; i < m; i++) {
                for (let j = 0; j < n; j++) {
                    const g0 = grid[i][j];
                    let low = 0;
                    let high = list.length - 1;
                    let ans = -1;
                    while (low <= high) {
                        const mid = Math.floor((low + high) / 2);
                        if (list[mid][0] >= g0) {
                            ans = mid;
                            low = mid + 1;
                        } else {
                            high = mid - 1;
                        }
                    }
                    if (ans !== -1) {
                        if (minSuffix[ans] < dp[t+1][i][j]) {
                            dp[t+1][i][j] = minSuffix[ans];
                        }
                    }
                }
            }
        }
    }

    let minCost = INF;
    for (let t = 0; t <= k; t++) {
        minCost = Math.min(minCost, dp[t][m-1][n-1]);
    }
    return minCost;
}
